function [data, auxData, metaData, txtData, weights] = mydata_Drosophila_melanogaster
% file generated by prt_mydata

%% set metaData
metaData.phylum     = 'Arthropoda';
metaData.class      = 'Insecta';
metaData.order      = 'Diptera';
metaData.family     = 'Drosophilidae';
metaData.species    = 'Drosophila_melanogaster';
metaData.species_en = 'fruit fly';

metaData.ecoCode.climate = {'A','B','C'};      % tropical–subtropical–temperate; cosmopolitan distribution
metaData.ecoCode.ecozone = {'TH','TN','TPa'};  % tropical humid, temperate nemoral, anthropogenic/peri-urban
metaData.ecoCode.habitat = {'0eTer','eiTi'};   % terrestrial; human-associated terrestrial habitats
metaData.ecoCode.embryo  = {'Th'};             % terrestrial, lecithotrophic eggs
metaData.ecoCode.migrate = {};                 % no migratory behaviour
metaData.ecoCode.food    = {'bjD','0iHs'};     % detritus/yeast substrates; human-associated food sources
metaData.ecoCode.gender  = {'D'};              % dioecious
metaData.ecoCode.reprod  = {'O'};              % oviparous

metaData.T_typical  = C2K(25); % K, body temp

metaData.data_0     = {'E0','ab','t1','t2','tj','Lb','L1','L2','Lj','ae','Wd_e','R','am'};
