data.tR_DR = [5 38;10 40;15 41;20 41;25 39;30 35;35 30;40 24;45 17;50 11;55 7;60 4;65 2;70 1;75 0.3];       units.tR_DR={'d','#/d'}; label.tR_DR={'age','fecundity (DR)'};  bibkey.tR_DR={'Ngo2019'}; temp.tR_DR=C2K(23); units.temp.tR_DR='K'; label.temp.tR_DR='temperature';
data.tR_HS = [5 30;10 34;15 36;20 34;25 30;30 24;35 18;40 13;45 9;50 6;55 4;60 2.5;65 1.2;70 0.6;75 0.2];   units.tR_HS={'d','#/d'}; label.tR_HS={'age','fecundity (HS)'};  bibkey.tR_HS={'Ngo2019'}; temp.tR_HS=C2K(23); units.temp.tR_HS='K'; label.temp.tR_HS='temperature';

%% set weights for all real data
weights = setweights(data, []);
%% set pseudodata and respective weights
[data, units, label, weights] = addpseudodata(data, units, label, weights);

%% pack auxData and txtData for output
auxData.temp = temp;
txtData.units = units;
txtData.label = label;
txtData.bibkey = bibkey;
%txtData.comment = comment;

